// Required header
headers: {
  "anthropic-beta": "context-management-2025-06-27"
}

// Python SDK
client = Anthropic(
  default_headers={"anthropic-beta": "context-management-2025-06-27"}
)

const response = await client.messages.create({
  model: "claude-4-sonnet-20251027", // Sonnet 4.5+
  messages: conversationHistory,
  max_tokens: 1000,
  tools: [
    {
      name: "memory_20250818", // Memory tool name
      description: "Store and retrieve information across conversations",
      input_schema: {
        type: "object",
        properties: {
          command: {
            type: "string",
            enum: ["view", "create", "str_replace", "insert", "delete", "rename"]
          },
          path: { type: "string" },
          text: { type: "string" },
          line_number: { type: "integer" },
          old_text: { type: "string" },
          new_text: { type: "string" }
        },
        required: ["command", "path"]
      }
    }
  ]
});

// Map Claude's memory commands to your storage backend
async function executeMemoryTool(toolInput) {
  const { command, path, text, line_number, old_text, new_text } = toolInput;

  // Security: restrict to /memories directory
  const normalizedPath = path.startsWith('/memories') 
    ? path 
    : `/memories${path}`;

  const fsPath = normalizedPath.replace('/memories', './memories');

  switch (command) {
    case 'view':
      if (fsPath.endsWith('/')) {
        // List directory
        return fs.readdirSync(fsPath);
      } else {
        // Read file
        return fs.readFileSync(fsPath, 'utf-8');
      }

    case 'create':
      fs.writeFileSync(fsPath, text, 'utf-8');
      return `Created ${fsPath}`;

    case 'str_replace':
      const content = fs.readFileSync(fsPath, 'utf-8');
      const updated = content.replace(old_text, new_text);
      fs.writeFileSync(fsPath, updated, 'utf-8');
      return `Updated ${fsPath}`;

    case 'insert':
      const lines = fs.readFileSync(fsPath, 'utf-8').split('\n');
      lines.splice(line_number - 1, 0, text);
      fs.writeFileSync(fsPath, lines.join('\n'), 'utf-8');
      return `Inserted at line ${line_number}`;

    case 'delete':
      fs.unlinkSync(fsPath);
      return `Deleted ${fsPath}`;

    case 'rename':
      const [oldPath, newPath] = text.split('→');
      fs.renameSync(
        oldPath.replace('/memories', './memories'),
        newPath.replace('/memories', './memories')
      );
      return `Renamed to ${newPath}`;

    default:
      throw new Error(`Unknown command: ${command}`);
  }
}

async function handleResponse(response) {
  // Check for tool use
  if (response.content && response.content[0].type === 'tool_use') {
    const toolCall = response.content[0];

    if (toolCall.name === 'memory_20250818') {
      // Execute memory tool
      const result = await executeMemoryTool(toolCall.input);

      // Send tool result back to Claude
      const toolResult = {
        type: 'tool_result',
        tool_use_id: toolCall.id,
        content: result
      };

      // Continue conversation with tool result
      return await client.messages.create({
        model: response.model,
        messages: [
          ...response.messages,
          { type: 'message', role: 'user', content: [toolResult] }
        ],
        max_tokens: response.max_tokens
      });
    }
  }

  return response;
}

// Claude autonomously decides to create memory:
await client.messages.create({
  model: "claude-4-sonnet-20251027",
  messages: conversationHistory,
  tools: [memoryTool],
  max_tokens: 1000
});

// Claude calls:
{
  command: "create",
  path: "/memories/auth-module-insights.md",
  text: "## Root Cause: JWT Token Expiry\n\nBug on line 847 of auth.ts:\n- JWT validation fails for tokens < 15 minutes\n- Fix: Add refresh token rotation\n- Tests: 3 passed, 1 failed (token expiry)"
}

// Claude automatically checks /memories at task start:
{
  command: "view",
  path: "/memories"
}

// Returns:
["auth-module-insights.md", "project-architecture.md", "todo.md"]

// Claude reads relevant file:
{
  command: "view",
  path: "/memories/auth-module-insights.md"
}

// Returns content:
"## Root Cause: JWT Token Expiry\n...\n"

// Claude updates existing memory:
{
  command: "str_replace",
  path: "/memories/auth-module-insights.md",
  old_text: "- Tests: 3 passed, 1 failed (token expiry)",
  new_text: "- Tests: 4 passed, 0 failed"
}

// Claude adds to todo list:
{
  command: "insert",
  path: "/memories/todo.md",
  line_number: 3,
  text: "- [ ] Add refresh token rotation to auth.ts"
}

// Claude removes outdated info:
{
  command: "delete",
  path: "/memories/old-architecture.md"
}

const response = await client.messages.create({
  model: "claude-4-sonnet-20251027",
  messages: conversationHistory,
  max_tokens: 1000,
  tools: [memoryTool],
  betas: ["context-management-2025-06-27"], // Enable both
  context_management: {
    edits: [
      {
        type: "clear_tool_uses_20250919",
        trigger: { type: "tool_uses", value: 2 },
        keep: { type: "tool_uses", value: 1 }
      }
    ],
    memory: {
      enabled: true,
      directory: "/memories" // Map to your storage
    }
  }
});

